(171, 1, '2025-01-07 17:08:56', '2025-01-07 17:08:56', '<!-- wp:gallery {\"linkTo\":\"none\"} -->\n<figure class=\"wp-block-gallery has-nested-images columns-default is-cropped\"><!-- wp:image {\"id\":29,\"sizeSlug\":\"large\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-large\"><img src=\"http://atpcgi.com/wp-content/uploads/2024/12/EX_Hill-House-_Overcast_01-1024x768.jpg\" alt=\"\" class=\"wp-image-29\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:image {\"id\":28,\"sizeSlug\":\"large\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-large\"><img src=\"http://atpcgi.com/wp-content/uploads/2024/12/EX_Hill-House-_DayLight_01-1024x768.jpg\" alt=\"\" class=\"wp-image-28\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:image {\"id\":18,\"sizeSlug\":\"large\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-large\"><img src=\"http://atpcgi.com/wp-content/uploads/2024/12/64-SB12_POV_06-1024x682.jpg\" alt=\"\" class=\"wp-image-18\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:image {\"id\":27,\"sizeSlug\":\"large\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-large\"><img src=\"http://atpcgi.com/wp-content/uploads/2024/12/240103_Riv-Residential-Building_Back-View_02-2-1024x768.jpg\" alt=\"\" class=\"wp-image-27\"/></figure>\n<!-- /wp:image --></figure>\n<!-- /wp:gallery -->\n\n<!-- wp:group {\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group\"><!-- wp:image {\"id\":17,\"sizeSlug\":\"large\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-large\"><img src=\"http://atpcgi.com/wp-content/uploads/2024/12/75-SB4_POV_04-1024x576.jpg\" alt=\"\" class=\"wp-image-17\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:group -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:flatsome/uxbuilder -->\n[ux_gallery ids=\"49,48,47,45,44,36,35,17,18,27,28,29,30,31,32,34,16,15,14\" lightbox_image_size=\"original\" type=\"masonry\" col_spacing=\