(197, 1, '2025-01-09 15:21:07', '2025-01-09 15:21:07', '<!-- wp:flatsome/uxbuilder -->\n[row]\n\n[col span=\"6\" span__sm=\"12\"]\n\n\n[/col]\n[col span=\"6\" span__sm=\"12\"]\n\n[ux_text font_size=\"3\" text_align=\"left\"]\n\n<p>If you’d like to discuss your projects, or would like to see more of our work, drop us a line.</p>\n<p>\n[/ux_text]\n[ux_text font_size=\"1.55\" text_color=\"rgb(255, 0, 0)\"]\n\n<p>STUDIO EMAIL: anhtaipham.visual@gmail.com</p>\n[/ux_text]\n\n[/col]\n\n[/row]\n[row]\n\n[col span__sm=\"12\"]\n\n\n[/col]\n\n[/row]\n[row]\n\n[col span__sm=\"12\"]\n\n\n[/col]\n\n[/row]\n\n<!-- /wp:flatsome/uxbuilder -->', 'Contacts', '', 'publish', 'closed', 'closed', '', 'contacts', '', '', '2025-01-09 15:32:29', '2025-01-09 15:32:29', '', 0, 'http://atpcgi.com/?page_id=197', 0, 'page', '', 0),
