(40, 'woopay-beta-merchantrecruitment-short-update-09MAY23', 'info', 'en_US', 'Increase conversions with WooPay — our fastest checkout yet', 'Be one of the first to try WooPay, our new express checkout feature. <br>Boost conversions by letting customers pay with a single click. <br><br>Update to the latest version of WooCommerce Payments to get started.', '{}', 'pending', 'woocommerce.com', '2025-01-07 14:38:16', NULL, 0, 'plain', '', 0, 0, 'info'),
(41, 'woocommerce-WCSubscriptions-June-2023-updated-needed', 'marketing', 'en_US', 'Action required: Security update of WooCommerce Subscriptions', '<strong>Your store requires a security update for the WooCommerce Subscriptions plugin</strong>. Please update the WooCommerce Subscriptions plugin immediately to address a potential vulnerability.', '{}', 'pending', 'woocommerce.com', '2025-01-07 14:38:16', NULL, 0, 'plain', '', 0, 0, 'info'),
(42, 'woocommerce-WCReturnsWarranty-June-2023-updated-needed', 'update', 'en_US', 'Action required: Security update of WooCommerce Returns and Warranty Requests extension', '<strong>Your store requires a security update for the Returns and Warranty Requests extension</strong>.  Please update to the latest version of the WooCommerce Returns and Warranty Requests extension immediately to address a potential vulnerability discovered on May 31.', '{}', 'pending', 'woocommerce.com', '2025-01-07 14:38:16', NULL, 0, 'plain', '', 0, 0, 'info'),
(43, 'woocommerce-WCOPC-June-2023-updated-needed', 'update', 'en_US', 'Action required: Security update of WooCommerce One Page Checkout', '<strong>Your shop requires a security update to address a vulnerability in the WooCommerce One Page Checkout extension</strong>. The fix for this vulnerability was released for this extension on June 13th. Please update immediately.', '{}', 'pending', 'woocommerce.com', '2025-01-07 14:38:16', NULL, 0, 'plain', '', 0, 0, 'info'),
(44, 'woocommerce-WCGC-July-2023-update-needed', 'update', 'en_US', 'Action required: Security update of WooCommerce GoCardless Extension', '<strong>Your shop requires a security update to address a vulnerability in the WooCommerce GoCardless extension</strong>. The fix for this vulnerability was released on July 4th. Please update immediately.', '{}', 'pending', 'woocommerce.com', '2025-01-07 14:38:16', NULL, 0, 'plain', '', 0, 0, 'info'),
(45, 'woocommerce-shipping-fedex-api-outage-2023-07-16', 'warning', 'en_US', 'Scheduled FedEx API outage — July 2023', 'On July 16 there will be a full outage of the FedEx API from 04:00 to 08:00 AM UTC. Due to planned maintenance by FedEx, you\'ll be unable to provide FedEx shipping rates during this time. Follow the link below for more information and recommendations on how to minimize impact.', '{}', 'pending', 'woocommerce.com', '2025-01-07 14:38:16', NULL, 0, 'plain', '', 0, 0, 'info'),
(46, 'wcship-2023-07-hazmat-update-needed', 'update', 'en_US', 'Action required: USPS HAZMAT compliance update for WooCommerce Shipping & Tax extension', '<strong>Your store requires an update for the WooCommerce Shipping extension</strong>. Please update to the latest version of the WooCommerce Shipping &amp; Tax extension immediately to ensure compliance with new USPS HAZMAT rules currently in effect.', '{}', 'pending', 'woocommerce.com', '2025-01-07 14:38:16', NULL, 0, 'plain', '', 0, 0, 'info'),
(47, 'woocommerce-WCStripe-Aug-2023-update-needed', 'update', 'en_US', 'Action required: Security update for WooCommerce Stripe plugin', '<strong>Your shop requires an important security update for the  WooCommerce Stripe plugin</strong>. The fix for this vulnerability was released on July 31. Please update immediately.', '{}', 'pending', 'woocommerce.com', '2025-01-07 14:38:16', NULL, 0, 'plain', '', 0, 0, 'info'),
(48, 'woocommerce-WCStripe-Aug-2023-security-updated', 'update', 'en_US', 'Security update of WooCommerce Stripe plugin', '<strong>Your store has been updated to the latest secure version of the WooCommerce Stripe plugin</strong>. This update was released on July 31.', '{}', 'pending', 'woocommerce.com', '2025-01-07 14:38:16', NULL, 0, 'plain', '', 0, 0, 'info'),
(49, 'woocommerce-WooPayments-Aug-2023-security-updated', 'update', 'en_US', 'Security update of WooPayments (WooCommerce Payments) plugin', '<strong>Your store has been updated to the more secure version of WooPayments (WooCommerce Payments)</strong>. This update was released on July 31.', '{}', 'pending', 'woocommerce.com', '2025-01-07 14:38:16', NULL, 0, 'plain', '', 0, 0, 'info'),
(50, 'avalara_q3-2023_noAvaTax', 'marketing', 'en_US', 'Automatically calculate VAT in real time', 'Take the effort out of determining tax rates and sell confidently across borders with automated tax management from Avalara AvaTax— including built-in VAT calculation when you sell into or across the EU and UK. Save time and stay compliant when you let Avalara do the heavy lifting.', '{}', 'pending', 'woocommerce.com', '2025-01-07 14:38:16', NULL, 0, 'plain', '', 0, 0, 'info'),
(51, 'woocommerce-usermeta-Sept2023-productvendors', 'update', 'en_US', 'Your store requires a security update', '<strong>Your shop needs an update to address a vulnerability in WooCommerce.</strong> The fix was released on Sept 15. Please update WooCommerce to the latest version immediately. <a href=\"https://developer.woocommerce.com/2023/09/16/woocommerce-vulnerability-reintroduced-from-7-0-1/\" />Read our developer update</a> for more information.', '{}', 'pending', 'woocommerce.com', '2025-01-07 14:38:16', NULL, 0, 'plain', '', 0, 0, 'info'),
(52, 'woocommerce-STRIPE-Oct-2023-update-needed', 'update', 'en_US', 'Action required: Security update for WooCommerce Stripe Gateway', '<strong>Your shop requires a security update to address a vulnerability in the WooCommerce Stripe Gateway</strong>. The fix for this vulnerability was released on October 17. Please update immediately.', '{}', 'pending', 'woocommerce.com', '2025-01-07 14:38:16', NULL, 0, 'plain', '', 0, 0, 'info'),
(53, 'amazon-mcf-reviews-2023-12-07', 'marketing', 'en_US', 'Enjoying Amazon MCF for WooCommerce?', 'We\'re Never Settle, the developers behind Amazon MCF for WooCommerce, and would be deeply honored to have your review. Reviews help immensely as other users can learn how MCF can solve their needs too! Not happy or need help? Please reach out for support and we’d love to make things right!', '{}', 'pending', 'woocommerce.com', '2025-01-07 14:38:16', NULL, 0, 'plain', '', 0, 0, 'info'),
(54, 'remove_estimated_deposits_2024', 'marketing', 'en_US', 'Estimated deposits are going away', 'To provide more accurate deposit information and support the expansion of instant deposits, estimated deposit details will no longer be available in WooPayments. We recommend upgrading to the latest version of WooPayments for more detailed balance status information.', '{}', 'pending', 'woocommerce.com', '2025-01-07 14:38:16', NULL, 0, 'plain', '', 0, 0, 'info'),
(55, 'sirt-woo-2024-11-xss-admin', 'update', 'en_US', 'An important update is required for WooCommerce', 'This update addresses a security vulnerability that could allow unauthorized access to administrative privileges on your site. <a href=\"https://developer.woocommerce.com/2024/12/03/woocommerce-9-4-3-and-woocommerce-9-3-4-available-now/\">Learn more</a>.\r\n<br><br>\r\n<strong>Please ensure your site is updated to the latest version to stay secure.</strong>', '{}', 'pending', 'woocommerce.com', '2025-01-07 14:38:16', NULL, 0, 'plain', '', 0, 0, 'info'),
(56, 'woocommerce-analytics-order-attribution-promotions-december-2024', 'marketing', 'en_US', 'Discover what drives your sales', 'Use our powerful <strong>Order Attribution</strong> extension to understand what truly drives your revenue. Track your sales journey, identify your most effective marketing channels, and optimize your sales strategy.', '{}', 'pending', 'woocommerce.com', '2025-01-07 14:38:16', NULL, 0, 'plain', '', 0, 0, 'info'),
(57, 'wc-admin-choosing-a-theme', 'marketing', 'en_US', 'Chọn giao diện?', 'Kiểm tra các giao diện tương thích với WooCommerce và chọn một giao diện phù hợp với thương hiệu và nhu cầu kinh doanh của bạn.', '{}', 'unactioned', 'woocommerce-admin', '2025-01-08 15:14:45', NULL, 0, 'plain', '', 0, 0, 'info'),
(58, 'wc-admin-add-first-product-note', 'email', 'en_US', 'Thêm sản phẩm đầu tiên của bạn', '{greetings}<br /><br />Tuyệt vời; bạn đã tạo một cửa hàng WooCommerce! Bây giờ là lúc để thêm sản phẩm đầu tiên của bạn và sẵn sàng để bắt đầu bán hàng.<br /><br />Có ba cách để thêm sản phẩm của bạn: bạn có thể <strong>tạo sản phẩm thủ công, nhập chúng cùng một lúc qua tệp CSV</strong> hoặc <strong>di chuyển chúng từ dịch vụ khác</strong>.<br /><br /><a href=\"https://woocommerce.com/document/managing-products/?utm_source=help_panel&amp;utm_medium=product\">Trực tiếp tài liệu của chúng tôi</a> để biết thêm thông tin hoặc chỉ để bắt đầu!', '{\"role\":\"administrator\"}', 'unactioned', 'woocommerce-admin', '2025-01-09 14:38:15', NULL, 0, 'plain', 'http://atpcgi.com/wp-content/plugins/woocommerce/images/admin_notes/dashboard-widget-setup.png', 0, 0, 'info'),
(59, 'wc-admin-mobile-app', 'info', 'en_US', 'Cài đặt ứng dụng di động Woo', 'Cài đặt ứng dụng di động WooCommerce để quản lý đơn đặt hàng, nhận thông báo bán hàng và xem các số liệu chính - mọi lúc mọi nơi.', '{}', 'unactioned', 'woocommerce-admin', '2025-01-09 14:38:15', NULL, 0, 'plain', '', 0, 0, 'info'),
(60, 'wc-admin-marketing-jetpack-backup', 'marketing', 'en_US', 'Bảo vệ Của hàng WooCommerce của bạn bằng Jetpack Backup.', 'Thời gian ngừng hoạt động của cửa hàng đồng nghĩa với việc mất doanh thu. Khôi phục bằng một cú nhấp chuột giúp bạn nhanh chóng hoạt động trở lại nếu có sự cố xảy ra.', '{}', 'unactioned', 'woocommerce-admin-notes', '2025-01-10 14:41:01', NULL, 0, 'thumbnail', 'http://atpcgi.com/wp-content/plugins/woocommerce/assets/images/admin_notes/marketing-jetpack-2x.png', 0, 0, 'info'),
(61, 'wc-admin-onboarding-payments-reminder', 'info', 'en_US', 'Bắt đầu chấp nhận thanh toán trên cửa hàng của bạn!', 'Nhận thanh toán với nhà cung cấp phù hợp với bạn - chọn từ hơn 100 cổng thanh toán cho WooCommerce.', '{}', 'unactioned', 'woocommerce-admin', '2025-01-12 16:26:22', NULL, 0, 'plain', '', 0, 0, 'info'),
(62, 'affirm_promo_Q1_2025', 'marketing', 'en_US', 'Save up to 50% on merchant fees with Affirm', 'Kickstart the year with buy now, pay later and get merchant rates as low as 2.9% + 30¢ per transaction for 30 days. Download the extension and complete your application from your WooCommerce dashboard by February 19, 2025 to claim the offer. Terms and conditions apply.', '{}', 'pending', 'woocommerce.com', '2025-01-21 15:03:41', NULL, 0, 'plain', '', 0, 0, 'info'),
(63, 'new-woo-brand-announcement-feb4-2025', 'marketing', 'en_US', 'Meet the new Woo', 'WooCommerce has a new look, but underneath, we’re still the same customizable, open-source ecommerce platform you know and love. Plus, we’ve got some major improvements to our platform and product on the way.', '{}', 'pending', 'woocommerce.com', '2025-02-04 20:54:55', NULL, 0, 'plain', '', 0, 0, 'info'),
(64, 'paypal_bnpl_au_promo_Q1_2025', 'marketing', 'en_US', 'Australian shoppers can Pay in 4 with PayPal', 'Enable Pay in 4 messaging to let Australian customers know that they can pay over time while you get paid up front and in full. Pay in 4 is included in PayPal Payments at no additional cost. Eligible buyers can pay in four interest-free payments for purchases of $30 to $2,000 AUD. Terms apply.', '{}', 'pending', 'woocommerce.com', '2025-02-12 15:04:52', NULL, 0, 'plain', '', 0, 0, 'info'),
(65, 'stripe_stripetax_q1_2025', 'marketing', 'en_US', 'Say goodbye to your tax woes', 'Stripe Tax automatically applies the correct sales tax, VAT, or GST, saving time while keeping you compliant. And with simple automatic filing, you can stop stressing at tax time and focus on growing instead.', '{}', 'pending', 'woocommerce.com', '2025-02-19 15:06:26', NULL, 0, 'plain', '', 0, 0, 'info'),
(66, 'printful_promo_q1_2025', 'marketing', 'en_US', 'New: sell print-on-demand products, risk-free', 'Expand your product line with Printful, now available in the WooCommerce Marketplace. Sell custom products with no upfront costs or inventory. This trusted supplier prints, packages, and ships for you, so you can focus on growing your store — and your next big idea.', '{}', 'pending', 'woocommerce.com', '2025-02-26 15:38:56', NULL, 0, 'plain', '', 0, 0, 'info'),
(67, 'paypal-braintree-sdk-depreciation-2025-02-20', 'update', 'en_US', 'Update required for your PayPal Braintree extension', 'To continue securely accepting payments, you must update your PayPal Braintree extension to version 3.2.4 or newer before June 30, 2025. Your current extension version will not support payment processing after this date due to an SSL certificate update.', '{}', 'pending', 'woocommerce.com', '2025-03-04 15:26:33', NULL, 0, 'plain', '', 0, 0, 'info'),
(68, 'woo-marketplace-two-year-subscriptions-rin-2025-03-17', 'marketing', 'en_US', 'Save 20% on new two-year subscriptions', 'We’ve introduced 20% off two-year subscriptions for all products* in the WooCommerce Marketplace. Lock in long-term savings and make sure your store never misses a beat. \r\n\r\n*Some exclusions apply. New purchases only.', '{}', 'pending', 'woocommerce.com', '2025-03-17 19:10:36', NULL, 0, 'plain', '', 0, 0, 'info'),
(69, 'viva_wallet_migration_q1_2025', 'update', 'en_US', 'Switch to the new Viva.com Smart Checkout', 'The Viva Wallet extension is no longer being updated and improved. To get the best Viva.com experience, move to the new Smart Checkout. It’s fast, secure, and fully compatible with the latest WooCommerce features.', '{}', 'pending', 'woocommerce.com', '2025-04-03 15:02:01', NULL, 0, 'plain', '', 0, 0, 'info'),
(70, 'stripe_orderstatus_bug_q2_2025', 'update', 'en_US', 'Action Required: Update Order Status Manager', 'Update to the latest Order Status Manager (v1.15.5+) to ensure payments are captured. Your version of WooCommerce Order Status Manager can interfere with order processing for payment gateways (including WooCommerce Stripe Gateway v9.2.0+), which may cause orders to process without capturing payment.', '{}', 'pending', 'woocommerce.com', '2025-04-03 15:02:01', NULL, 0, 'plain', '', 0, 0, 'info'),
(71, 'wc-admin-real-time-order-alerts', 'info', 'en_US', 'Nhận thông báo đặt hàng theo thời gian thực ở mọi nơi', 'Nhận thông báo về hoạt động của cửa hàng, bao gồm các đơn đặt hàng mới và đánh giá sản phẩm trực tiếp trên thiết bị di động của bạn bằng ứng dụng Woo.', '{}', 'unactioned', 'woocommerce-admin', '2025-04-07 15:00:08', NULL, 0, 'plain', '', 0, 0, 'info'),
(72, 'WooCommerce-Stripe-Gateway-Update-April-2025', 'update', 'en_US', 'Action required: Update WooCommerce Stripe Gateway to v9.4.1', '<strong>An important update for WooCommerce Stripe Payment Gateway has been released</strong>. Version 9.4.1 addresses performance issues and payment method visibility problems that occurred in version 9.4.0. Please update as soon as possible for optimal store performance. Please read <a href=\"https://developer.woocommerce.com/2025/04/18/https://developer.woocommerce.com/2025/04/18/developer-advisory-stripe-payment-gateway-9-4-1-release/\" /> this advisory</a> for more information.', '{}', 'pending', 'woocommerce.com', '2025-04-19 14:47:54', NULL, 0, 'plain', '', 0, 0, 'info'),
(73, 'WooCommerce-Stripe-Gateway-Update-Info-April-2025', 'update', 'en_US', 'WooCommerce Stripe Gateway has been updated to v9.4.1', '<strong>WooCommerce Stripe Payment Gateway was recently updated</strong>. Version 9.4.1 addresses performance issues and payment method visibility problems that occurred in version 9.4.0. No further action is required. Please read <a href=\"https://developer.woocommerce.com/2025/04/18/https://developer.woocommerce.com/2025/04/18/developer-advisory-stripe-payment-gateway-9-4-1-release/\" /> this advisory post </a>for more information.', '{}', 'pending', 'woocommerce.com', '2025-04-19 14:47:54', NULL, 0, 'plain', '', 0, 0, 'info'),
(74, 'klaviyo_q2_2025', 'marketing', 'en_US', 'Tailor your marketing with data-driven automation', 'Deliver personalized experiences at scale, simplify your stack, and make your data work for you using Klaviyo’s best-in-class marketing extension for Woo. With advanced segmentation based on actual customer behavior, you can send email and SMS messages that drive revenue and increase loyalty — without adding complexity', '{}', 'pending', 'woocommerce.com', '2025-05-03 15:51:09', NULL, 0, 'plain', '', 0, 0, 'info'),
(75, 'uk-vat-notice-2025-04-30', 'warning', 'en_US', 'UK VAT numbers are no longer supported', 'Due to recent HM Revenue &amp; Customs (HMRC) VAT API changes, your EU VAT Number for WooCommerce extension can no longer validate UK VAT numbers. HMRC now requires merchants to register an API key, which this extension does not currently support. We recommend EU/UK VAT Validation Manager for WooCommerce as a replacement', '{}', 'pending', 'woocommerce.com', '2025-05-05 15:26:37', NULL, 0, 'plain', '', 0, 0, 'info'),
(76, 'payson-retirement-2025', 'update', 'en_US', 'Payson Form Retirement', 'Svea Bank is discontinuing the Payson service; the last date for transactions is August 31, 2025. As a result, the Payson Form extension has been removed from WooCommerce.com. Documentation remains available.', '{}', 'pending', 'woocommerce.com', '2025-05-13 16:08:30', NULL, 0, 'plain', '', 0, 0, 'info'),
(77, 'paypal_q2_2025', 'marketing', 'en_US', 'Power up sales with Pay Later messaging', 'Help increase your sales and grow cart sizes by letting customers know they have flexible payment options. Merchants see up to an 11% sales lift when they add Pay Later messaging — plus, it integrates seamlessly with your PayPal checkout.', '{}', 'pending', 'woocommerce.com', '2025-05-22 14:38:43', NULL, 0, 'plain', '', 0, 0, 'info'),
(78, 'paypal-braintree-sdk-depreciation-2025-05-30', 'update', 'en_US', 'Action required: Update the PayPal Braintree extension', 'Your PayPal Braintree extension is using an outdated SDK and will stop processing payments after June 30, 2025, due to a root SSL certificate expiration. To avoid service disruption, update to version 3.2.4 or newer immediately.', '{}', 'pending', 'woocommerce.com', '2025-05-30 14:44:43', NULL, 0, 'plain', '', 0, 0, 'info'),
(79, 'tento_q2_2025', 'marketing', 'en_US', 'Get your free business credit score', 'Strong business credit is the key to better deals, stronger partnerships, and sustainable growth. Tento Business Credit Monitoring helps you catch risks early, secure better financing, and fuel smarter growth — with no impact to your credit.', '{}', 'pending', 'woocommerce.com', '2025-06-04 15:19:06', NULL, 0, 'plain', '', 0, 0, 'info'),
(80, 'woopayments-multibanco-alipay-wechat-launch-2025-06-23', 'marketing', 'en_US', 'Multibanco, AliPay and WeChat now available in WooPayments', 'Multibanco, AliPay, and WeChat Pay are now available in WooPayments! Offer trusted local payment methods to customers in key global markets and boost international sales. Geo restrictions apply.', '{}', 'pending', 'woocommerce.com', '2025-06-23 15:04:06', NULL, 0, 'plain', '', 0, 0, 'info'),
(81, 'woopayments-new-lpms-2025-06-30', 'marketing', 'en_US', 'Get the POS built specifically for Woo stores', 'Introducing WooCommerce POS, our new point-of-sale solution built to get you up and running quickly with in-person sales. Search products, scan barcodes, apply coupons, and send email receipts — right in the WooCommerce mobile app, with all of your online and physical sales synced in real time — no extra setup required', '{}', 'pending', 'woocommerce.com', '2025-06-30 14:47:26', NULL, 0, 'plain', '', 0, 0, 'info'),
(82, 'tiktok-webinar-promo-july2025', 'marketing', 'en_US', 'You\'re Invited: TikTok for WooCommerce Webinar', 'Join us for a free webinar with our friends at TikTok on Tuesday, July 8, at 4 pm UTC. We\'ll cover creative tips and best practices for making content that turns views into sales.', '{}', 'pending', 'woocommerce.com', '2025-06-30 14:47:26', NULL, 0, 'plain', '', 0, 0, 'info'),
(83, 'wc-admin-manage-orders-on-the-go', 'info', 'en_US', 'Quản lý đơn hàng của bạn khi đang di chuyển', 'Tìm kiếm đơn đặt hàng, thông tin khách hàng và xử lý hoàn tiền chỉ bằng một cú nhấp chuột với ứng dụng Woo.', '{}', 'unactioned', 'woocommerce-admin', '2025-07-06 15:13:09', NULL, 0, 'plain', '', 0, 0, 'info'),
(84, 'woopayments-grabpay-launch-2025-07-07', 'marketing', 'en_US', 'GrabPay now available in WooPayments', 'Offer GrabPay through WooPayments and make checkout easier for customers across Southeast Asia. Enable it today and expand your reach with a payment method they know and trust.', '{}', 'pending', 'woocommerce.com', '2025-07-07 14:58:34', NULL, 0, 'plain', '', 0, 0, 'info'),
(85, 'BFCM-25-Survey', 'marketing', 'en_US', 'You’re invited: Take our quick BFCM survey and get 25% off', 'We’re gathering insights on how businesses prepare for peak sales moments like Black Friday and Cyber Monday — so we can better support you. Take our quick 8-minute survey to share your thoughts and get 25% off your next WooCommerce extension as a thank you.', '{}', 'pending', 'woocommerce.com', '2025-07-15 15:33:26', NULL, 0, 'plain', '', 0, 0, 'info'),
(86, 'woohoo10-coupon', 'marketing', 'en_US', 'Celebrate and save with WooCommerce 10.0', 'To mark this milestone release, get 10% off extensions and themes in the official Woo Marketplace. Use code WOOHOO10 at checkout to save on essential tools that help grow your business. Offer ends August 15, 2025. Terms and conditions apply.', '{}', 'unactioned', 'woocommerce.com', '2025-07-21 15:37:58', NULL, 0, 'plain', '', 0, 0, 'info'),
(87, 'paypaladvantage_q3_2025', 'marketing', 'en_US', 'Add PayPal Checkout and earn up to $1,000*', 'PayPal Checkout can boost conversion by up to 46% and average order value by up to 62% with no disruption to your checkout. New US merchants who activate by August 31 save 25% on transaction fees for 6 months. Excludes Venmo. Terms apply.*', '{}', 'pending', 'woocommerce.com', '2025-07-23 15:22:59', NULL, 0, 'plain', '', 0, 0, 'info'),
(88, 'stripe_optimizedcheckout_upgrade_q3_2025', 'marketing', 'en_US', 'Upgrade for a faster, more flexible Stripe checkout', 'You\'re not on the latest WooCommerce Stripe Payment Gateway version. Upgrade to version 9.8 to access Stripe\'s Optimized Checkout Suite and leverage AI models to dynamically surface the most relevant payment methods for each customer, including BNPL, local options, and one-click Link checkout.', '{}', 'pending', 'woocommerce.com', '2025-08-13 15:59:07', NULL, 0, 'plain', '', 0, 0, 'info'),
(89, 'stripe_optimizedcheckout_enable_q3_2025', 'marketing', 'en_US', 'Unlock dynamic payments and sell more', 'You’re on the latest WooCommerce Stripe Payment Gateway — now unlock its full potential by enabling the Optimized Checkout Suite. It uses AI models to dynamically surface the most relevant payment methods for each customer, helping you boost conversions.', '{}', 'pending', 'woocommerce.com', '2025-08-13 15:59:07', NULL, 0, 'plain', '', 0, 0, 'info'),
(90, 'stripe_optimizedcheckout_promotion_q3_2025', 'marketing', 'en_US', 'Upgrade to Stripe for a faster, more flexible checkout', 'Unlock dynamic payments with Stripe’s Optimized Checkout Suite — now available with the WooCommerce Stripe Payment Gateway. Leverage AI models to dynamically surface the most relevant payment methods for each customer, including BNPL, local options, and one-click Link checkout.', '{}', 'pending', 'woocommerce.com', '2025-08-15 14:46:02', NULL, 0, 'plain', '', 0, 0, 'info'),
(91, 'woo-subscription-gifting-bundling-2025-08-18', 'marketing', 'en_US', 'Grow recurring revenue with gifting', 'WooCommerce Subscriptions now includes gifting. Customers can buy subscriptions for others, helping you reach new shoppers and grow recurring revenue with less effort. Update to the latest version of Subscriptions (7.8.0) to start offering gifting.', '{}', 'pending', 'woocommerce.com', '2025-08-20 15:07:56', NULL, 0, 'plain', '', 0, 0, 'info'),
(92, 'stripe_optimizedcheckout_competitors_q3_2025', 'marketing', 'en_US', 'Upgrade to the official WooCommerce Stripe Payment Gateway', 'Unlock dynamic payments with Stripe’s Optimized Checkout Suite — now available with the WooCommerce Stripe Payment Gateway. Use AI models to dynamically surface the most relevant payment methods for each customer, including BNPL, local options, and one-click checkout with Link.', '{}', 'pending', 'woocommerce.com', '2025-08-28 14:52:48', NULL, 0, 'plain', '', 0, 0, 'info'),
(93, 'UPS-promo-RIN-WCS-Aug-25', 'marketing', 'en_US', 'Get up to $100 off your first UPS shipments', 'For a limited time, merchants new to UPS can get up to $10 off their first 10 UPS labels on WooCommerce Shipping. Simplify your shipping, lower costs, and keep customers happy with fast, affordable options built right into your store dashboard.', '{}', 'pending', 'woocommerce.com', '2025-09-10 15:49:20', NULL, 0, 'plain', '', 0, 0, 'info'),
(94, 'UPS-promo-RIN-WCST-Aug-25', 'marketing', 'en_US', 'Get up to $100 off your first UPS shipments', 'For a limited time, merchants new to UPS can get up to $10 off their first 10 UPS labels on WooCommerce Shipping. Simplify your shipping, lower costs, and keep customers happy with fast, affordable options built right into your store dashboard.', '{}', 'pending', 'woocommerce.com', '2025-09-10 15:49:20', NULL, 0, 'plain', '', 0, 0, 'info'),
(95, 'square_ordersync_upgrade_q3_2025', 'marketing', 'en_US', 'You asked, we delivered — order sync is here for Square', 'Update your Square extension to v5.0 to access <a href=\"https://woocommerce.com/document/woocommerce-square/sync-settings/sync-orders-between-woocommerce-and-square/\">automatic order syncing</a>. Manage your online sales in Square, keep reports accurate, and save time with order updates visible across both platforms.', '{}', 'pending', 'woocommerce.com', '2025-09-11 14:40:12', NULL, 0, 'plain', '', 0, 0, 'info'),
(96, 'klaviyo_q3_2025', 'marketing', 'en_US', 'Smarter marketing starts with Woo x Klaviyo', 'Personalize every customer interaction with Klaviyo, Woo\'s preferred marketing automation solution. Advanced segmentation based on real customer behavior lets you create email and SMS campaigns focused on driving loyalty and revenue. So you can grow sales while simplifying your stack.', '{}', 'pending', 'woocommerce.com', '2025-09-17 14:54:05', NULL, 0, 'plain', '', 0, 0, 'info'),
(97, 'pinterest_q3_20252', 'marketing', 'en_US', 'More visibility, smarter campaigns', 'Connect your store to Pinterest via the Conversions API, a new feature in the latest version of our official extension. Target the right shoppers, track performance, and optimize campaigns for more sales. Get started today — connect and sync your catalog using the Conversions API.', '{}', 'pending', 'woocommerce.com', '2025-09-24 15:16:06', NULL, 0, 'plain', '', 0, 0, 'info'),
(98, 'wc-admin-performance-on-mobile', 'info', 'en_US', 'Theo dõi hiệu suất cửa hàng của bạn trên thiết bị di động', 'Theo dõi doanh số và sản phẩm hoạt động hiệu quả cao của bạn bằng ứng dụng Woo.', '{}', 'unactioned', 'woocommerce-admin', '2025-10-04 16:29:31', NULL, 0, 'plain', '', 0, 0, 'info'),
(99, 'pinterest_q4_2025', 'marketing', 'en_US', 'Maximize conversions with Pinterest', 'Connect your store to Pinterest via the Conversions API, now part of our official extension. Target the right shoppers, track performance, and optimize campaigns for more sales. Sync your catalog and create your first ad today.', '{}', 'pending', 'woocommerce.com', '2025-10-22 14:40:40', NULL, 0, 'plain', '', 0, 0, 'info'),
(100, 'paypaladvantage_q4_2025', 'marketing', 'en_US', 'PayPal Checkout offer: Get 40% back on fees for 3 months', 'Download and activate PayPal Payments in your WooCommerce admin, then complete your first transaction by 15 December 2025 to get 40% back on PayPal transaction fees — up to £2,000 for 3 months. PayPal Checkout works with your existing checkout. See terms: paypal.com/uk/campaign/paypalmerchantpromotion/terms.', '{}', 'pending', 'woocommerce.com', '2025-11-05 14:51:58', NULL, 0, 'plain', '', 0, 0, 'info'),
(101, 'reddit_q4_2025', 'marketing', 'en_US', 'New: Reach high-intent shoppers on Reddit', 'Sync your catalog and pixel with Reddit for WooCommerce. Launch your ads faster on Reddit and connect with their 400M+ weekly active users and shoppers who turn to this platform for authentic conversations and recommendations.', '{}', 'pending', 'woocommerce.com', '2025-11-14 14:38:22', NULL, 0, 'plain', '', 0, 0, 'info'),
(102, 'bfcm_general_sale_q4_2025', 'marketing', 'en_US', 'Save up to 40% on extensions and themes', 'For a limited time, take up to 40% off nearly everything in our Marketplace. It’s the perfect moment to give your store a holiday boost and level up for 2026. Sale ends December 2, 2025, at 14:00 UTC.', '{}', 'pending', 'woocommerce.com', '2025-11-19 15:53:34', NULL, 0, 'plain', '', 0, 0, 'info'),
(103, 'paypal-carding-recaptcha-dec-25', 'update', 'en_US', 'Activate PayPal fraud management', 'PayPal detected increased suspicious card activity in market. Please enable fraud protection in your PayPal Payment settings by enabling CAPTCHA for PayPal Payments.', '{}', 'pending', 'woocommerce.com', '2025-12-04 14:52:59', NULL, 0, 'plain', '', 0, 0, 'info'),
(104, 'Googleupdate_q4_2025', 'marketing', 'en_US', 'Make every ad dollar count this holiday season', 'Google for WooCommerce now includes Budget Recommendations. Install the latest version and get personalized suggestions on where to optimize campaign budgets to reach more holiday shoppers this season.', '{}', 'pending', 'woocommerce.com', '2025-12-05 15:05:20', NULL, 0, 'plain', '', 0, 0, 'info'),
(105, 'holiday_shipping_deadlines_WCST_2025', 'marketing', 'en_US', 'Holiday shipping deadlines', 'Ensure your packages arrive before December 25. Verify your exact ship-by date for your destination, carrier, and mail class.', '{}', 'pending', 'woocommerce.com', '2025-12-12 15:15:26', NULL, 0, 'plain', '', 0, 0, 'info'),
(106, 'holiday_shipping_deadlines_WCS_2025', 'marketing', 'en_US', 'Holiday shipping deadlines', 'Ensure your packages arrive before December 25. Verify your exact ship-by date for your destination, carrier, and mail class.', '{}', 'pending', 'woocommerce.com', '2025-12-12 15:15:26', NULL, 0, 'plain', '', 0, 0, 'info');
INSERT INTO `wpgi_wc_admin_notes` (`note_id`, `name`, `type`, `locale`, `title`, `content`, `content_data`, `status`, `source`, `date_created`, `date_reminder`, `is_snoozable`, `layout`, `image`, `is_deleted`, `is_read`, `icon`) VALUES
(107, 'snap_q4_2025', 'marketing', 'en_US', 'New: Reach a new audience on Snapchat', '88% of Snapchatters love to shop, and 40% aren\'t active on other social platforms. Connect with them and grow your business using Snapchat for WooCommerce, our new official extension. Sync your products, launch ad campaigns, and track results — all from your Woo dashboard.', '{}', 'pending', 'woocommerce.com', '2025-12-19 14:53:31', NULL, 0, 'plain', '', 0, 0, 'info'),
(108, 'stripe_agenticcommerce_3PDS_q4_2025', 'marketing', 'en_US', 'Get more from Stripe with the official extension', 'Switch to the official extension co-developed with Stripe for the latest features and best performance. Get access to personalized checkout options, early support for AI shopping through Stripe’s <a href=\"https://woocommerce.com/posts/stripe-agentic-commerce-suite-for-woocommerce/\">Agentic Commerce Suite</a>, and more.', '{}', 'pending', 'woocommerce.com', '2025-12-19 14:53:31', NULL, 0, 'plain', '', 0, 0, 'info'),
(109, 'WC10.4.3-security-update-12-22-2025', 'update', 'en_US', 'An important update is required for WooCommerce', '<strong>Please update to WooCommerce 10.4.3 to resolve a security issue.</strong> This update addresses an issue with the WooCommerce Store API that may have made guest order information visible to other logged in users. See the <a href=\"https://developer.woocommerce.com/2025/12/22/store-api-vulnerability-patched-in-woocommerce-8-1/\" target=\"_blank\">Woo Developer blog</a> for more information.', '{}', 'pending', 'woocommerce.com', '2025-12-23 15:09:03', NULL, 0, 'plain', '', 0, 0, 'info'),
(110, 'wc-admin-edit-products-on-the-move', 'info', 'en_US', 'Chỉnh sửa sản phẩm khi di chuyển', 'Chỉnh sửa và tạo sản phẩm mới từ thiết bị di động của bạn bằng ứng dụng Woo', '{}', 'unactioned', 'woocommerce-admin', '2026-01-07 17:07:35', NULL, 0, 'plain', '', 0, 0, 'info'),
(111, 'downloads-sub-Jan2026-RIN', 'marketing', 'en_US', 'WooCommerce Subscription Downloads is now part of WooCommerce Subscriptions', 'WooCommerce Subscriptions now allows you to include simple and variable downloadable products with your subscriptions. Streamline your subscription downloads by updating to the latest version of WooCommerce Subscriptions today.', '{}', 'pending', 'woocommerce.com', '2026-01-07 17:07:36', NULL, 0, 'plain', '', 0, 0, 'info'),
(112, 'paypal-carding-recaptcha-jan-26', 'update', 'en_US', 'Fraud protection is now required — enable today', 'Card networks like Visa and Mastercard now require fraud prevention controls, and non-compliance may result in fines and processing restrictions. Please enable reCAPTCHA in your PayPal Payments settings to help protect your store and maintain compliance.', '{}', 'pending', 'woocommerce.com', '2026-01-13 14:47:06', NULL, 0, 'plain', '', 0, 0, 'info'),
(113, 'USPS API Migration_RIN_Jan2026', 'marketing', 'en_US', 'Upgrade to USPS Shipping REST API by January 25', 'USPS is retiring the legacy Web Tools API on January 25, 2026. If you’re using the USPS Shipping Method extension with the legacy API, live USPS shipping rates will longer be shown at checkout. Migrate to the REST API now to avoid disruption.', '{}', 'pending', 'woocommerce.com', '2026-01-14 14:40:42', NULL, 0, 'plain', '', 0, 0, 'info'),
(114, 'existing_square_bitcoin_promotion_q1_2026', 'marketing', 'en_US', 'Take bitcoin payments in Square with 0% fees in 2026', 'Your Square POS can now accept in-person bitcoin payments, with near-instant settlement and no chargebacks. Enable it today and pay zero fees through 2026. T&amp;Cs apply.', '{}', 'pending', 'woocommerce.com', '2026-01-22 14:39:32', NULL, 0, 'plain', '', 0, 0, 'info'),
(115, 'prospects_square_bitcoin_promotion_q1_2026', 'marketing', 'en_US', 'Take bitcoin payments in Square with 0% fees in 2026', 'Accept in-person <a href=\"https://woocommerce.com/posts/square-bitcoin-launch\">bitcoin payments</a> with Square POS — and pay zero fees on all bitcoin transactions through 2026. Get near-instant settlement and total protection from chargebacks.', '{}', 'pending', 'woocommerce.com', '2026-01-22 14:39:32', NULL, 0, 'plain', '', 0, 0, 'info'),
(116, 'reddit_q1_2026', 'marketing', 'en_US', 'Start advertising on Reddit with a $1,000 bonus', 'Make the most of our new Reddit integration with $1,000 in Reddit Ads! For a limited time, new advertisers who spend $1,000 in Reddit Ads Manager over 30 days will get $1,000 in ad credit. Your bonus credit unlocks automatically when you hit $1,000 in spend. Use your credit within 30 days.', '{}', 'pending', 'woocommerce.com', '2026-02-05 15:49:22', NULL, 0, 'plain', '', 0, 0, 'info'),
(117, 'Googleupdate_q1_2026', 'marketing', 'en_US', 'Make every ad dollar count', 'Google for WooCommerce now includes Budget Recommendations. Promote your products across Google — from Search to YouTube and beyond — and get personalized suggestions on where to optimize campaign budgets to reach more shoppers.', '{}', 'pending', 'woocommerce.com', '2026-02-11 15:20:34', NULL, 0, 'plain', '', 0, 0, 'info'),
(118, 'Mailchimp-API-maintenance-feb-2026', 'update', 'en_US', 'Mailchimp Maintenance Feb 28', 'Mailchimp will be carrying out planned API maintenance on February 28 from 11am – 4pm EST. During that time, you may see brief sync interruptions in Mailchimp for WooCommerce. Most data will catch up automatically. See the <a href=\"https://developer.woocommerce.com/2026/02/27/mailchimp-api-maintenance-february-28/\" target=\"_blank\">Woo Developer blog</a> for more information.', '{}', 'pending', 'woocommerce.com', '2026-02-27 14:56:50', NULL, 0, 'plain', '', 0, 0, 'info'),
(119, 'RIN-WC-Security-Update-admin-update-March-2026', 'update', 'en_US', 'An important update is required for WooCommerce', '<strong>Update to WooCommerce 10.5.3 or the latest version to resolve a security issue.</strong> This update addresses a vulnerability in WooCommerce versions 5.4 to 10.5.2 that could have permitted unauthorized admin account access. See the <a href=\"https://developer.woocommerce.com/2026/03/02/store-api-vulnerability-patched-in-woocommerce-5-4/\" target=\"_blank\">Woo Developer blog</a> for more information.', '{}', 'unactioned', 'woocommerce.com', '2026-03-03 15:41:04', NULL, 0, 'plain', '', 0, 0, 'info');
